var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마…!","JPN":"お母さん……！","ENG":"Mommy...!","TWN":"媽媽……！"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이쪽이야! 빨리 와요!","JPN":"こっちだよ！　早く来て！","ENG":"This way! Quickly!","TWN":"這邊！快來！"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"또 이 환각이네.","JPN":"またこの幻覚。","ENG":"It's this hallucination again.","TWN":"又是這個幻覺。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"환자복을 입은 아이의 멀어져가는 뒷모습.","JPN":"患者服を着た、遠ざかってゆく子どもの後ろ姿。","ENG":"The one where the girl in the hospital gown is getting further away from me.","TWN":"身穿病服的孩子漸漸遠去的背影。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"아무리 빨리 달리고, 손을 뻗어도, 멀어져만 가는 뒷모습.","JPN":"いくら早く走って、手を伸ばしても、遠ざかるばかりの後ろ姿。","ENG":"No matter how fast I run and reach out my hand, she only gets further away.","TWN":"無論我跑得有多快，無論我如何挽留，這個背影都會離我越來越遠。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"그래… 알고 있어.","JPN":"そう……わかってる。","ENG":"Yeah... I know.","TWN":"我知道……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"이제와서 붙잡으려고 하기엔…","JPN":"今さら引き止めるには……","ENG":"That it's too late for me to...","TWN":"我現在想試著去抓住她……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"너무 늦은 거겠지.","JPN":"遅すぎる。","ENG":"try and hold her.","TWN":"可能已經太晚了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그래도…","JPN":"それでも……","ENG":"But still...","TWN":"可是……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"미련이 남는 건 역시 어쩔 수 없네.","JPN":"未練が残るのはしょうがないね。","ENG":"I can't help but regret it.","TWN":"我不禁感到遺憾。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPRIT_FLOOR_BEHIND_HOSPITAL","text":{"KOREA":"짧은 여행이었지만 즐거웠어요, 엄마.","JPN":"短い旅行だったけど、楽しかったよ。お母さん。","ENG":"It was a short trip, but it was fun, Mommy.","TWN":"雖然旅行很短暫，但我很開心，媽媽。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPRIT_FLOOR_BEHIND_HOSPITAL","text":{"KOREA":"또 만나면, 한 번 더 가요.","JPN":"また会ったら、もう一度行こう。","ENG":"Let's do it again the next time we meet.","TWN":"再見面的話，我們再去一次吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"넌…?","JPN":"あなたは……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하늘…?","JPN":"空……？","ENG":"The sky...?","TWN":"天空……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가 또 꿈을 꾸고 있나?","JPN":"私はまた夢を見てるのか？","ENG":"Is this another dream?","TWN":"難道我又做夢了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"저게…","JPN":"あれは……","ENG":"What's...","TWN":"那個……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"대체 뭐지?","JPN":"いったい何だ？","ENG":"all that?","TWN":"到底怎麼回事？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"전부…","JPN":"全部……","ENG":"It's all...","TWN":"全部……"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_1"},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"통째로 사라졌어.","JPN":"丸ごと消えた。","ENG":"just completely gone.","TWN":"全部消失了。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_2"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"이번에도 환각일까? 아니면 이면세계의 변덕일까?","JPN":"また幻？　それとも裏世界の気まぐれ？","ENG":"Is this another hallucination? Or just a whim of the Counterside?","TWN":"難道這也是幻覺？還是異界的問題？"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_3"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"날 삼켰던 그 거대한 심연의 요새가, 이젠 눈앞에 흔적만 남아있었어.","JPN":"私を飲み込んだあの目の前の巨大な深淵の要塞が、もう痕跡だけ残っていた。","ENG":"The massive abyssal fortress that swallowed me is left in ruins in front of my eyes.","TWN":"曾經吞噬我的那個巨大的深淵要塞，如今在我眼前只剩下些許殘骸。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_4"},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"폭발에서 운 좋게 살아남았다기엔 뭔가 이상했지.","JPN":"爆発から運よく生き残ったにしては、何かが変だった。","ENG":"Something felt off that I was lucky enough to survive the blast.","TWN":"奇怪的是，我竟然在爆炸中倖存了下來。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_5"},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"그건…","JPN":"あれは……","ENG":"Because...","TWN":"這……"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_6"},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"폭발로 사라진 흔적이 아니었거든.","JPN":"爆発で消えた跡じゃなかったから。","ENG":"those weren't traces of an explosion taking place here.","TWN":"不，這些痕跡不是因為爆炸而產生的。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_7"},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"게다가, 보름달 표면처럼 반듯하게 잘려 나간 그 단면 주위엔…","JPN":"しかも、満月の表面のように綺麗に切り取られたあの断面の周りには……","ENG":"Also, on the edges of the surfaces cut clean like the surface of the moon...","TWN":"而且，周圍這些像月球表面一樣被平整地切掉的斷面……"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_8"},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"나에게 어떤 메시지를 전하려는 듯, 녹음 무성한 나무들이 팔을 뻗고 있었어.","JPN":"私にメッセージを送るかのように、緑豊かな木々が枝を伸ばしていた。","ENG":"there were lush trees stretching out their branches, as if they were trying to send me a message.","TWN":"還有這些鬱鬱蔥蔥的樹木伸出的雙臂，仿佛在向我傳達著某種資訊。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_9"},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Yeah.","TWN":"……嗯。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_10"},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"이건 환각도, 꿈도 아니야.","JPN":"これは幻でも、夢でもない。","ENG":"This isn't a dream or a hallucination.","TWN":"這不是幻覺，也不是夢。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_11"},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"기다려.","JPN":"待って。","ENG":"Wait for me.","TWN":"等著我。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_12"},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"네가 어디에 있든, 찾아내겠어.","JPN":"あなたがどこにいても、必ず見つけだす。","ENG":"Wherever you are, I'll find you.","TWN":"無論你在哪裡，我都會找到你。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_13"},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"반드시… 데리러 갈 테니까.","JPN":"必ず……迎えに行くから。","ENG":"I'll... come get you, no matter what.","TWN":"我一定……會來接你。"},"stage":{"bg":"FLOOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CHAMBER_S_ENGINEER_IN_TRAILER_14"},{"id":"L6_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"우리 제대로 온 거 맞지? 클리파인지 신성파인지 하는 그 이상한 에너지가 감지된 곳.","JPN":"ここで合ってんだよな？　クリファとか神聖波とか、その変なエネルギーが感知された場所って。","ENG":"This is the place, right? Where the Qlipha or whatever it's called energy was detected.","TWN":"就是這個地方了吧？無論是逆卡巴拉還是什麼的能量，反正是感應到奇怪反應的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"근데 아무것도 없잖아! 여기까지 오는 좌표를 뚫으려고, 나흘 밤을 꼬박 샜는데!","JPN":"でも、なんもねえじゃねえか！　ここまでに来るのに4日も寝ずに座標を調べたのによ！","ENG":"But there's nothing here! I stayed up all night for four days just to find the coordinates to get here!","TWN":"但是！這裡！什麼也沒有！我四天沒睡覺，就是為了能找到來到這裡的座標！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"나무가 자라는 이면세계는 흔치 않지. 확실히 평범한 곳은 아니야.","JPN":"木が生えてる裏世界は珍しい。確かにただの場所ではなさそうだ。","ENG":"It's uncommon for trees to grow in the Counterside. Which means this place is no ordinary place.","TWN":"在異界通常不長樹木。這裡絕對不是個普通的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>말단 녀석</color>이 말한 아주 대단한 아티팩트는 보이지 않는 것 같군.","JPN":"だが、<color=#ffd34c>下っ端のやつ</color>が言ったとおり、とびきりのアーティファクトは見当たらない。","ENG":"But I don't see the Artifact that the <color=#ffd34c>rookie</color> was talking about.","TWN":"但我好像沒看見<color=#ffd34c>新人</color>說的什麼人造神器。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"잔류 침식파를 분석해봤을 땐 차원균열의 흔적 같은데…","JPN":"残留侵食波を分析してみると、次元亀裂の跡のようだが……","ENG":"Analyzing the residuals of the Corruption ray, it looks like traces of a dimensional rift...","TWN":"根據殘留的侵蝕波分析來看，似乎有次元裂縫的痕跡……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"이것도 한 번 추적해볼까?","JPN":"これも追跡してみるか？","ENG":"Should I track this one too?","TWN":"要嘗試下跟蹤這個嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"침식파가 섞인 균열을 쫓았다간 침식소굴이나 허수공간에 빠질지도 모른다. 죽기 딱 좋은 계획이지.","JPN":"侵食波が混ざった亀裂を追いかけると、侵食巣窟や虚数空間に落ちるかもしれない。死ぬのに絶好の計画だな。","ENG":"Chasing after a rift that's been mixed with Corruption rays will lead you to a Corruption pit or even the imaginary space. It's the perfect plan for a suicide.","TWN":"順著混有侵蝕波的裂縫前進，我們可能會掉進侵蝕坑或虛空次元。你擬了一個完美的自殺計畫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"아주 마음에 드는군.","JPN":"気に入ったぞ。","ENG":"I love it.","TWN":"很好，很不錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"헤헤, 그치?","JPN":"へへっ、そうだろ？","ENG":"Hehe, I know, right?","TWN":"嘿嘿，對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"파형 수집은 끝났으니 빨리 돌아가서 해독해보자!","JPN":"波形収集は終わったんだから、早く戻って解読しようぜ！","ENG":"I'm done collecting the waveforms. Let's go back and analyze them!","TWN":"我們已經完成了波形的收集，盡快回去解讀它們吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"자리에 앉았으니, 해독부터 당장 시작할까?","JPN":"座ったところで、まず解読から行きますか！","ENG":"Now that we're sitting down, shall we start analyzing?","TWN":"怎麼說，現在就開始嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그 전에 관리국 놈들이 꼬일지도 모르니 좌표 선회부터 하자고.","JPN":"その前に、管理局のやつらがついてくるかもしれないから座標旋回からしよう。","ENG":"Before that, let's circle around the coordinates just in case that pesky Administration catches wind.","TWN":"不能讓管理局也聽到了風聲，我們還是處理下這裡的座標吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"네 네, 덩치에 안 어울리게 참 섬세하시구만…","JPN":"へいへい、図体に似合わねえ繊細さだな……","ENG":"Yeah, yeah. You're awfully thorough for someone who's that bulky...","TWN":"好好好，沒想到你塊頭那麼大，心思倒是很細膩。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"야, 근데 어디서 되게 재밌는 냄새 나지 않아?","JPN":"おい、てかどっかでめっちゃ面白そうなニオイがしねえか？","ENG":"Hey, you do also smell something funny?","TWN":"嗯？好像有什麼很香的氣味？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그래…","JPN":"ああ……","ENG":"Yeah...","TWN":"是啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"우리 배에 여자를 태운 기억은 없는데 말이지.","JPN":"この船に女を乗せた記憶はないんだがな。","ENG":"I don't remember boarding a girl on our ship.","TWN":"我不記得我們船上有任何女人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"응…?","JPN":"あ……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"크허헉…!","JPN":"くはあっ……！","ENG":"Kuh...!","TWN":"咳咳……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"움직이지 마! 움직이면 이 녀석 머리통이 날아갈 테니까!","JPN":"動くな！　動いたらこいつの頭をぶっ飛ばす！","ENG":"Don't move! So much as twitch and your friend's brain's gonna be splattered on the wall!","TWN":"別動！只要你動一下，這傢伙的頭就會開花了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그래? 그렇단 말이지?","JPN":"そうか。そうくるか。","ENG":"Oh? Is that so, eh?","TWN":"喔？是這樣嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…오지 말라니까!","JPN":"……来るなって！","ENG":"...I said, don't move!","TWN":"……我說了！不要過來！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"야 야! 깡통! 오지 말라잖아! 내 머리통 날아가는 꼴 보고 싶어?!","JPN":"おい、おい！　ボロ缶！　来るなって言ってんだろ！　俺の大事な頭がぶっ飛ばされてもいいのか！？","ENG":"Hey! Tin can! She said, don't move! You wanna see my head get blown off?!","TWN":"喂、喂！鐵桶！都說了叫你不要過來了！你想看我的腦袋開花嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"…나 같아도 좀 궁금할 것 같긴 하지만.","JPN":"……俺もちっと気になるけどよ。","ENG":"... I mean, I'd be kinda curious too, but.","TWN":"……呃，不過說實話我也有點想看。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"아무튼! 나 죽는다고! 망할! 이 여자가 시키는 대로 해!","JPN":"とにかく！　俺が死ぬから！　くそ！　この女の言うとおりにしろ！","ENG":"Anyway! She'll kill me! Dammit! Just do as she says!","TWN":"反正！我會死的！該死啊！這個女人讓你做什麼就做什麼！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"언제부터 우리 배에 타고 있던 거지?","JPN":"いつからこの船に乗ってたんだ？","ENG":"When did you get on our ship?","TWN":"你從什麼時候開始上我們的船的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…방금 전.","JPN":"……ついさっきから。","ENG":"...Just before.","TWN":"……就在剛剛。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하이재킹의 목적은?","JPN":"ハイジャックした目的は？","ENG":"And what's your purpose?","TWN":"那麼你的目的呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"가야 할 곳이 있어.","JPN":"行きたいところがある。","ENG":"There's some place I need to go.","TWN":"我要去一個地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"목적지까지만 움직이면 네 친구가 다치는 일은 없을 거야.","JPN":"目的地まで行ってくれれば、あなたの友だちには怪我はさせない。","ENG":"If you take me to my destination, your friend won't get hurt.","TWN":"只要你送我過去，你的朋友就不會受傷。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그래?","JPN":"そうか。","ENG":"Oh yeah?","TWN":"喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 우리가 목적지에 데려다 줄 때까지 버틸 정도로 정신이 온전치는 못한 것 같은데.","JPN":"だが、俺らが送っても目的地に着くまで耐えられないほど精神的に病んでそうだな。","ENG":"But I don't think you can make it to your destination with your current state of mind.","TWN":"但我認為你的狀態不可能堅持到到達目的地。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아… 하… 쓸데없는 소릴…","JPN":"はあ……はあ……余計なことを……","ENG":"*Huff...* *Huff...* Stop talking...","TWN":"呼……呼……少廢話……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 그러네? 침식파 노출? 아니면 금단증상인가? 상태를 봐선 꽤 말기 수준인가 본데?","JPN":"おお、そうだな？　侵食波露出？　それとも禁断症状か？　状態を見ると、かなり末期っぽいな？","ENG":"Yeah, you're right! Corruption ray exposure? Or is it withdrawal? From the looks of it, it's in its late stages.","TWN":"哈哈，你還真說對啦！侵蝕波暴露？還是戒斷症狀？從你的情況來看，已經到了末期了喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"내가 도와줄까? 나 갖고 있는 약 많아. 옵션도 맞춰 줄게.","JPN":"俺が助けてやろか？　俺、薬は結構持ってるぞ。オプションもあんたに合わせてやるよ。","ENG":"Want me to help? I got tons of drugs. I'll even mix and match them to your needs.","TWN":"需要我幫你嗎？我帶了很多藥。我還可以讓你選喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정신 사납게 굴지 말고… 어서 출발이나 해.","JPN":"気が散る……早く出発しろ。","ENG":"Stop annoying me and... start the ship.","TWN":"別耍什麼把戲……趕緊出發。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"배짱은 좋았지만, 제안은 거절하지.","JPN":"度胸は認めるが、その提案は断ろう。","ENG":"I like your guts, but I'll have to refuse on that offer.","TWN":"雖然你很有膽量，但我拒絕你的提議。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"지금 붙잡은 녀석이 우리 연료비와 맞바꿀 정도로 소중한 친구는 아니라서 말이야.","JPN":"今お前が人質にしてるやつが、俺たちの燃料費と交換できるほどに大切な仲間ではないからな。","ENG":"That guy you're holding hostage isn't important enough for us to use our fuel on him.","TWN":"你剛剛抓的這個人，不值得用我們的燃油費來交換。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"너무해!","JPN":"人でなし！","ENG":"Oh come on!","TWN":"喂喂！太過分了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 녀석이 죽고 나면, 그 다음은 네 차례야.","JPN":"こいつを殺したら、次はあなたの番だ。","ENG":"Once he's dead, you're next.","TWN":"這傢伙死了之後，就輪到你了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 커다란 망치가 방아쇠보다 빠를 거라 착각하는 건 아니겠지?","JPN":"そのデカい槌が引き金より早いと勘違いしてるわけじゃないだろう？","ENG":"You don't think that huge hammer is going to be faster than me pulling a trigger, do you?","TWN":"你不會幻想這樣的大錘會快過扳機吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그게 궁금하면, 한 번 해보던지.","JPN":"気になったら、やってみろ。","ENG":"Well, we can certainly find out if you want.","TWN":"如果你想知道，可以試一試。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"咳……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"자 자, 피차 바쁜 사람들끼리 싸우지들 말자고요.","JPN":"さてさて、お互い忙しいですし、ケンカはやめましょう。","ENG":"Now, now. We're all busy people, so let's stop the fighting.","TWN":"好了好了，大家都很忙，就不要吵架了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"급할수록 돌아가라는 말도 있잖아요? 대화로 해결해보는 건 어때요?","JPN":"急がば回れって言うじゃないですか。会話で解決しましょうよ。","ENG":"You know what they say, haste makes waste. How about we talk it out?","TWN":"不是有句話叫作欲速則不達？不如我們好好溝通一下？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"허구한 날 책만 읽더니, 웬일로 우리 일에 끼어드는군.","JPN":"いつも本ばかり呼んでるくせに、俺たちの仕事にちょっかいを出すなんて珍しいな。","ENG":"What's the occasion? You haven't done anything but read your book.","TWN":"我們之間的事不用你來管，回去讀你的書去。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>말단 친구</color>.","JPN":"<color=#ffd34c>下っ端君</color>。","ENG":"<color=#ffd34c>Rookie</color>.","TWN":"<color=#ffd34c>新人</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 원래 제가 사사로운 일에 끼어드는 편이 아니긴 한데요.","JPN":"はは、僕は元々他人事に首を突っ込むタイプじゃないんですけど。","ENG":"Haha, I'm not usually the type to get involved in other people's business.","TWN":"哈哈，我本來不是那種會干涉別人私事的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저분에게는 개인적인 용무가 있어서 말이죠.","JPN":"あの方には個人的な用件がありまして。","ENG":"But I have personal business with her.","TWN":"只不過我也有些事想要找她。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"넌… 또 뭐지?","JPN":"今度は……なんだ？","ENG":"Who... are you?","TWN":"你……又是誰？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"전 주시윤이라고 합니다.","JPN":"僕はアキヤマ・シリュウと言います。","ENG":"My name is Joo Shiyoon.","TWN":"我叫周時雲。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"짧게 소개하자면, 보물을 찾아 온차원을 유랑하는 검객이자 교섭가랄까요?","JPN":"簡単に自己紹介すると、宝物を探して全次元を流浪する剣客でかつ交渉家ってところですね。","ENG":"To briefly introduce myself, let's just say that I'm a swordsman and negotiator wandering all dimensions in search of treasure.","TWN":"簡單來說，應該是一個遊走於次元間，尋找寶藏的劍客和談判者？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"흥, 그래봐야 여기 있는 해적 놈들과 한통속이겠지.","JPN":"フン、でもここにいる海賊の野郎どもとグルだろう。","ENG":"Hmph. To me you're just another pirate.","TWN":"哼，這麼說，你和這裡的海盜是一夥兒的吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"난 해적 말 같은 건 믿지 않아.","JPN":"私は海賊の言葉なんて信じない。","ENG":"And I don't trust what pirates say.","TWN":"我可不會相信海盜的話。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하… 명색이 말단 선원이라, 아니라고 부정은 못하겠네요.","JPN":"ハハ……立派な下っ端船員なので、違うとは否定できませんね。","ENG":"Haha... Since I am the rookie crew mate, I can't say that I'm not.","TWN":"哈哈……我確實還是一名新人水手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 저도 무턱대고 당신을 해칠 생각이 없습니다.","JPN":"でも、僕もうかつにあなたを攻撃するつもりはありません。","ENG":"But I also have no intention of harming you.","TWN":"但我對你也沒有惡意。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"만약 당신의 행선지가 저희와 같다면 굳이 이렇게 싸울 필요도 없겠죠.","JPN":"もしあなたの行き先が僕たちと同じなら、こうやって戦う必要もないでしょう。","ENG":"You see, if we're headed toward the same place, then I don't see why we have to fight.","TWN":"如果我們的目的地一致，就更沒有爭吵的必要了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가… 당신들 목적지와 같다고…?","JPN":"私の目的地が……あなたたちと同じ……？","ENG":"You... and I are headed toward the same place...?","TWN":"你說……我們的目的地一樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그러니 흥분은 잠시 가라앉히고 얘기라도 나눠보자고요, 프리하트 부인.","JPN":"だから、少し落ち着いてお話でもしませんか？　プラハト夫人。","ENG":"So, how about you calm down so we can talk, Ms. Freeheart?","TWN":"所以，先冷靜一下，我們聊聊吧，普立哈特夫人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"何……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"날… 어떻게…?","JPN":"どうして……私のことを……？","ENG":"How... do you...?","TWN":"你……怎麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"휴, 큰일 날 뻔했네.","JPN":"ふう、事が大きくなるところだったぜ。","ENG":"Phew, that was a close one.","TWN":"呼，剛才可真驚險。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"시간 끌어줘서 고마워, 말단 소년.","JPN":"時間を稼いでくれてありがとうな、下っ端少年。","ENG":"Thanks for buying us time, rookie.","TWN":"謝謝你爭取時間，菜鳥。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 뭘 이 정도로요.","JPN":"ハハ、いやいや。","ENG":"Haha, don't mention it.","TWN":"哈哈，小意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 시간만 끌 목적이었다기엔 진짜 이름을 맞힌 것 같은 반응이더군.","JPN":"だが、時間稼ぎというより彼女のことを知ってるような口ぶりだったな。","ENG":"But for just buying time, her reaction tells me that you got her name right.","TWN":"不過，與其說拖延時間，倒不如說他猜到了真名。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"아는 사람인가?","JPN":"知り合いか？","ENG":"Do you know her?","TWN":"你認識她？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"正是。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"첫 만남이 좀 험상궂긴 했지만…","JPN":"初対面の時は少し険しい感じでしたけど……","ENG":"Our first encounter was a little unpleasant, but...","TWN":"雖然第一次見面有一番波折，不過……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희의 이번 여정을 도와줄 가이드 분이십니다.","JPN":"今度、僕たちの旅をサポートしてくれる、ガイドの方です。","ENG":"she'll be our guide who'll help us on this journey.","TWN":"她是能為我們這段旅程提供幫助的嚮導。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"뭐야. 탄창이 비어있잖아? 총알도 없이 우리 배를 하이재킹하려고 한 거야?","JPN":"んだよ。弾倉が空っぽじゃねえか。弾丸もねえくせに、俺らの船をハイジャックしようとしたのか？","ENG":"Huh? Her mag was empty. So she tried to hijack our ship without any bullets?","TWN":"什麼啊。彈匣是空的？你憑一把空槍，就想劫持我們的船？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"배짱 좋은데?","JPN":"すげえ度胸だな。","ENG":"She's got guts.","TWN":"膽子很大嘛？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"소리만 들어도 알 수 있는 블러핑에 속은 건 너 뿐일 거다, 라울.","JPN":"音だけでもわかるブラフに騙されたのはお前だけだ、ラウル。","ENG":"Everyone knew from just hearing the gun that it was a bluff except you, Raúl.","TWN":"任何人聽到這聲音都知道槍裡沒子彈吧？拉烏爾。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"쳇, 청각보조기를 업그레이드라도 해야지 원.","JPN":"ちっ、補聴器をアップグレードしねえとな。","ENG":"Tch! Guess I gotta upgrade my hearing aids then.","TWN":"嘖，我現在就去升級我的助聽器，立刻！馬上！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"저거 봐. 엄청 큰 나무가 있어.","JPN":"あれ見て。とても大きな木がある。","ENG":"Look over there. There's a huge tree.","TWN":"看那邊，獵犬。那裡有一顆很大的樹喔。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"집도 보여. 사람들이 모여 사나 봐.","JPN":"おウチも見えるよ。人たちが集まって住んでるみたい。","ENG":"Shepherd also sees a house. Looks like people live over there.","TWN":"還能看到房子裡似乎有人居住。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"내가 가서, 널 고쳐줄 똑똑한 어른을 데려올게.","JPN":"シェパードがあなたを直してくれる頭がいい大人を連れてくるね。","ENG":"Shepherd will go over there and find a smart adult who'll fix you.","TWN":"牧羊犬去找個聰明的大人來修理你。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그러니까, 여기서 조금만 기다려.","JPN":"だから、ここでちょっとだけ待ってて。","ENG":"So wait here for me.","TWN":"所以，待在這裡等我。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처.","JPN":"ラッチャー。","ENG":"Lurcher.","TWN":"獵犬。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};